package com.taskflow.service;

import com.taskflow.dto.LoginRequest;
import com.taskflow.dto.LoginResponse;
import com.taskflow.dto.RegisterRequest;
import com.taskflow.entity.User;
import com.taskflow.repository.UserRepository;
import com.taskflow.security.JwtTokenProvider;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.ArgumentCaptor;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.security.crypto.password.PasswordEncoder;

import java.util.Map;
import java.util.Optional;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)
class AuthServiceTest {

    @Mock
    private UserRepository userRepository;

    @Mock
    private PasswordEncoder passwordEncoder;

    @Mock
    private JwtTokenProvider jwtTokenProvider;

    @InjectMocks
    private AuthService authService;

    private RegisterRequest validRegisterRequest;
    private LoginRequest validLoginRequest;
    private User savedUser;

    @BeforeEach
    void setUp() {
        validRegisterRequest = new RegisterRequest();
        validRegisterRequest.setUsername("testuser");
        validRegisterRequest.setPassword("password123");
        validRegisterRequest.setDisplayName("Test User");

        validLoginRequest = new LoginRequest();
        validLoginRequest.setUsername("testuser");
        validLoginRequest.setPassword("password123");

        savedUser = new User();
        savedUser.setId(1L);
        savedUser.setUsername("testuser");
        savedUser.setPassword("$2a$10$encodedPassword");
        savedUser.setDisplayName("Test User");
    }

    // ========== Register Tests ==========

    // AC1: register success returns user info
    @Test
    void register_withValidRequest_shouldReturnUserInfo() {
        when(userRepository.findByUsername("testuser")).thenReturn(Optional.empty());
        when(passwordEncoder.encode("password123")).thenReturn("$2a$10$encodedPassword");
        when(userRepository.save(any(User.class))).thenReturn(savedUser);

        Map<String, Object> result = authService.register(validRegisterRequest);

        assertNotNull(result);
        assertEquals(1L, result.get("id"));
        assertEquals("testuser", result.get("username"));
        assertEquals("Test User", result.get("displayName"));
        // Should not contain password in the response
        assertFalse(result.containsKey("password"));
    }

    // AC1: register should hash password with BCrypt
    @Test
    void register_shouldHashPasswordBeforeSaving() {
        when(userRepository.findByUsername("testuser")).thenReturn(Optional.empty());
        when(passwordEncoder.encode("password123")).thenReturn("$2a$10$encodedPassword");
        when(userRepository.save(any(User.class))).thenReturn(savedUser);

        authService.register(validRegisterRequest);

        ArgumentCaptor<User> userCaptor = ArgumentCaptor.forClass(User.class);
        verify(userRepository).save(userCaptor.capture());

        User capturedUser = userCaptor.getValue();
        assertEquals("$2a$10$encodedPassword", capturedUser.getPassword());
        assertNotEquals("password123", capturedUser.getPassword());
    }

    // AC1: register should set all fields correctly on saved entity
    @Test
    void register_shouldSetAllFieldsOnUser() {
        when(userRepository.findByUsername("testuser")).thenReturn(Optional.empty());
        when(passwordEncoder.encode(anyString())).thenReturn("$2a$10$encoded");
        when(userRepository.save(any(User.class))).thenReturn(savedUser);

        authService.register(validRegisterRequest);

        ArgumentCaptor<User> userCaptor = ArgumentCaptor.forClass(User.class);
        verify(userRepository).save(userCaptor.capture());

        User capturedUser = userCaptor.getValue();
        assertEquals("testuser", capturedUser.getUsername());
        assertEquals("Test User", capturedUser.getDisplayName());
    }

    // AC2: duplicate username should throw exception
    @Test
    void register_withDuplicateUsername_shouldThrowException() {
        when(userRepository.findByUsername("testuser")).thenReturn(Optional.of(savedUser));

        assertThrows(RuntimeException.class, () -> authService.register(validRegisterRequest));
        verify(userRepository, never()).save(any(User.class));
    }

    // ========== Login Tests ==========

    // AC4: login success returns token and expiresIn
    @Test
    void login_withValidCredentials_shouldReturnTokenAndExpiresIn() {
        when(userRepository.findByUsername("testuser")).thenReturn(Optional.of(savedUser));
        when(passwordEncoder.matches("password123", "$2a$10$encodedPassword")).thenReturn(true);
        when(jwtTokenProvider.generateToken(1L)).thenReturn("jwt-token-string");

        LoginResponse result = authService.login(validLoginRequest);

        assertNotNull(result);
        assertEquals("jwt-token-string", result.getToken());
        assertEquals(86400, result.getExpiresIn());
    }

    // AC5: wrong password should throw exception
    @Test
    void login_withWrongPassword_shouldThrowException() {
        when(userRepository.findByUsername("testuser")).thenReturn(Optional.of(savedUser));
        when(passwordEncoder.matches("password123", "$2a$10$encodedPassword")).thenReturn(false);

        assertThrows(RuntimeException.class, () -> authService.login(validLoginRequest));
        verify(jwtTokenProvider, never()).generateToken(any());
    }

    // AC6: nonexistent user should throw same exception type (no user enumeration)
    @Test
    void login_withNonexistentUser_shouldThrowException() {
        when(userRepository.findByUsername("testuser")).thenReturn(Optional.empty());

        assertThrows(RuntimeException.class, () -> authService.login(validLoginRequest));
        verify(passwordEncoder, never()).matches(anyString(), anyString());
        verify(jwtTokenProvider, never()).generateToken(any());
    }

    // BR7: same exception type for both wrong password and nonexistent user
    @Test
    void login_wrongPasswordAndNonexistentUser_shouldThrowSameExceptionType() {
        // Wrong password case
        when(userRepository.findByUsername("testuser")).thenReturn(Optional.of(savedUser));
        when(passwordEncoder.matches("password123", "$2a$10$encodedPassword")).thenReturn(false);

        Exception wrongPasswordException = assertThrows(RuntimeException.class,
                () -> authService.login(validLoginRequest));

        // Nonexistent user case
        LoginRequest noUserRequest = new LoginRequest();
        noUserRequest.setUsername("nobody");
        noUserRequest.setPassword("password123");
        when(userRepository.findByUsername("nobody")).thenReturn(Optional.empty());

        Exception noUserException = assertThrows(RuntimeException.class,
                () -> authService.login(noUserRequest));

        assertEquals(wrongPasswordException.getClass(), noUserException.getClass());
    }

    // ========== GetCurrentUser Tests ==========

    // AC7: getCurrentUser returns user info
    @Test
    void getCurrentUser_withValidUserId_shouldReturnUserInfo() {
        when(userRepository.findById(1L)).thenReturn(Optional.of(savedUser));

        Map<String, Object> result = authService.getCurrentUser(1L);

        assertNotNull(result);
        assertEquals(1L, result.get("id"));
        assertEquals("testuser", result.get("username"));
        assertEquals("Test User", result.get("displayName"));
        assertFalse(result.containsKey("password"));
    }

    // getCurrentUser with nonexistent userId should throw
    @Test
    void getCurrentUser_withNonexistentUserId_shouldThrowException() {
        when(userRepository.findById(999L)).thenReturn(Optional.empty());

        assertThrows(RuntimeException.class, () -> authService.getCurrentUser(999L));
    }

    // Verify response shape: exactly 3 keys for register
    @Test
    void register_responseShape_shouldContainExactlyIdUsernameDisplayName() {
        when(userRepository.findByUsername("testuser")).thenReturn(Optional.empty());
        when(passwordEncoder.encode(anyString())).thenReturn("$2a$10$encoded");
        when(userRepository.save(any(User.class))).thenReturn(savedUser);

        Map<String, Object> result = authService.register(validRegisterRequest);

        assertEquals(3, result.size());
        assertTrue(result.containsKey("id"));
        assertTrue(result.containsKey("username"));
        assertTrue(result.containsKey("displayName"));
    }

    // Verify response shape: exactly 3 keys for getCurrentUser
    @Test
    void getCurrentUser_responseShape_shouldContainExactlyIdUsernameDisplayName() {
        when(userRepository.findById(1L)).thenReturn(Optional.of(savedUser));

        Map<String, Object> result = authService.getCurrentUser(1L);

        assertEquals(3, result.size());
        assertTrue(result.containsKey("id"));
        assertTrue(result.containsKey("username"));
        assertTrue(result.containsKey("displayName"));
    }

    // Verify login expiresIn is always 86400
    @Test
