            MvcResult result = mockMvc.perform(post("/api/auth/login")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isOk())
                    .andReturn();

            String responseBody = result.getResponse().getContentAsString();
            String token = objectMapper.readTree(responseBody).get("token").asText();

            assertTrue(jwtTokenProvider.validateToken(token), "Returned token should be valid");
        }

        // AC5: wrong password → 401
        @Test
        void shouldReturn401_whenWrongPassword() throws Exception {
            LoginRequest req = buildLoginRequest("loginuser", "wrongpassword");

            mockMvc.perform(post("/api/auth/login")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isUnauthorized())
                    .andExpect(jsonPath("$.message").exists());
        }

        // AC6: nonexistent user → 401
        @Test
        void shouldReturn401_whenUserDoesNotExist() throws Exception {
            LoginRequest req = buildLoginRequest("nonexistent", "password123");

            mockMvc.perform(post("/api/auth/login")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isUnauthorized())
                    .andExpect(jsonPath("$.message").exists());
        }

        // BR7: no user enumeration — same error message for wrong password vs nonexistent user
        @Test
        void shouldReturnSameErrorMessage_forWrongPasswordAndNonexistentUser() throws Exception {
            MvcResult wrongPwResult = mockMvc.perform(post("/api/auth/login")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(buildLoginRequest("loginuser", "wrongpassword"))))
                    .andExpect(status().isUnauthorized())
                    .andReturn();

            MvcResult noUserResult = mockMvc.perform(post("/api/auth/login")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(buildLoginRequest("nonexistent", "password123"))))
                    .andExpect(status().isUnauthorized())
                    .andReturn();

            String wrongPwMsg = objectMapper.readTree(wrongPwResult.getResponse().getContentAsString())
                    .get("message").asText();
            String noUserMsg = objectMapper.readTree(noUserResult.getResponse().getContentAsString())
                    .get("message").asText();

            assertEquals(wrongPwMsg, noUserMsg,
                    "Error messages should be identical to prevent user enumeration");
        }

        // Empty body → 400
        @Test
        void shouldReturn400_whenEmptyBody() throws Exception {
            mockMvc.perform(post("/api/auth/login")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content("{}"))
                    .andExpect(status().isBadRequest());
        }
    }

    // =============================================
    // GET /api/auth/me
    // =============================================

    @Nested
    class MeEndpoint {

        private User testUser;
        private String validToken;

