package com.taskflow.controller;

import com.fasterxml.jackson.databind.ObjectMapper;
import com.taskflow.dto.LoginRequest;
import com.taskflow.dto.RegisterRequest;
import com.taskflow.entity.User;
import com.taskflow.repository.UserRepository;
import com.taskflow.security.JwtTokenProvider;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.http.MediaType;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.test.web.servlet.MockMvc;
import org.springframework.test.web.servlet.MvcResult;
import org.springframework.transaction.annotation.Transactional;

import static org.hamcrest.Matchers.*;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

@SpringBootTest
@AutoConfigureMockMvc
@Transactional
class AuthControllerIntegrationTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private PasswordEncoder passwordEncoder;

    @Autowired
    private JwtTokenProvider jwtTokenProvider;

    @BeforeEach
    void setUp() {
        userRepository.deleteAll();
    }

    // ========== Helper Methods ==========

    private String toJson(Object obj) throws Exception {
        return objectMapper.writeValueAsString(obj);
    }

    private User createUserInDb(String username, String rawPassword, String displayName) {
        User user = new User();
        user.setUsername(username);
        user.setPassword(passwordEncoder.encode(rawPassword));
        user.setDisplayName(displayName);
        return userRepository.save(user);
    }

    private RegisterRequest buildRegisterRequest(String username, String password, String displayName) {
        RegisterRequest req = new RegisterRequest();
        req.setUsername(username);
        req.setPassword(password);
        req.setDisplayName(displayName);
        return req;
    }

    private LoginRequest buildLoginRequest(String username, String password) {
        LoginRequest req = new LoginRequest();
        req.setUsername(username);
        req.setPassword(password);
        return req;
    }

    // =============================================
    // POST /api/auth/register
    // =============================================

    @Nested
    class RegisterEndpoint {

        // AC1: register success 201 with id, username, displayName
        @Test
        void shouldReturn201WithUserInfo_whenValidRequest() throws Exception {
            RegisterRequest req = buildRegisterRequest("newuser", "password123", "New User");

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isCreated())
                    .andExpect(jsonPath("$.id").isNumber())
                    .andExpect(jsonPath("$.username").value("newuser"))
                    .andExpect(jsonPath("$.displayName").value("New User"))
                    .andExpect(jsonPath("$.password").doesNotExist());
        }

        // AC1: contract verification — response has exactly id, username, displayName
        @Test
        void shouldReturnExactResponseSchema_whenRegisterSuccess() throws Exception {
            RegisterRequest req = buildRegisterRequest("schemauser", "password123", "Schema Test");

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isCreated())
                    .andExpect(jsonPath("$.id").exists())
                    .andExpect(jsonPath("$.username").exists())
                    .andExpect(jsonPath("$.displayName").exists())
                    .andExpect(jsonPath("$.token").doesNotExist())
                    .andExpect(jsonPath("$.expiresIn").doesNotExist())
                    .andExpect(jsonPath("$.password").doesNotExist())
                    .andExpect(jsonPath("$.createdAt").doesNotExist());
        }

        // AC2: duplicate username 409
        @Test
        void shouldReturn409_whenUsernameAlreadyExists() throws Exception {
            createUserInDb("existing", "password123", "Existing User");

            RegisterRequest req = buildRegisterRequest("existing", "password456", "Another User");

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isConflict())
                    .andExpect(jsonPath("$.message").exists());
        }

        // AC11: username too short (2 chars) → 400
        @Test
        void shouldReturn400_whenUsernameTooShort() throws Exception {
            RegisterRequest req = buildRegisterRequest("ab", "password123", "Name");

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isBadRequest());
        }

        // AC11: username at lower boundary (3 chars) → 201
        @Test
        void shouldReturn201_whenUsernameExactly3Chars() throws Exception {
            RegisterRequest req = buildRegisterRequest("abc", "password123", "Name");

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isCreated())
                    .andExpect(jsonPath("$.username").value("abc"));
        }

        // AC11: username at upper boundary (50 chars) → 201
        @Test
        void shouldReturn201_whenUsernameExactly50Chars() throws Exception {
            String username50 = "a".repeat(50);
            RegisterRequest req = buildRegisterRequest(username50, "password123", "Name");

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isCreated())
                    .andExpect(jsonPath("$.username").value(username50));
        }

        // AC11: username too long (51 chars) → 400
        @Test
        void shouldReturn400_whenUsernameTooLong() throws Exception {
            RegisterRequest req = buildRegisterRequest("a".repeat(51), "password123", "Name");

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isBadRequest());
        }

        // AC12: password too short (7 chars) → 400
        @Test
        void shouldReturn400_whenPasswordTooShort() throws Exception {
            RegisterRequest req = buildRegisterRequest("validuser", "1234567", "Name");

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isBadRequest());
        }

        // AC12: password at boundary (8 chars) → 201
        @Test
        void shouldReturn201_whenPasswordExactly8Chars() throws Exception {
            RegisterRequest req = buildRegisterRequest("validuser", "12345678", "Name");

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isCreated());
        }

        // AC13: displayName empty → 400
        @Test
        void shouldReturn400_whenDisplayNameEmpty() throws Exception {
            RegisterRequest req = buildRegisterRequest("validuser", "password123", "");

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isBadRequest());
        }

        // AC13: displayName at upper boundary (100 chars) → 201
        @Test
        void shouldReturn201_whenDisplayNameExactly100Chars() throws Exception {
            String name100 = "a".repeat(100);
            RegisterRequest req = buildRegisterRequest("validuser", "password123", name100);

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isCreated())
                    .andExpect(jsonPath("$.displayName").value(name100));
        }

        // AC13: displayName too long (101 chars) → 400
        @Test
        void shouldReturn400_whenDisplayNameTooLong() throws Exception {
            RegisterRequest req = buildRegisterRequest("validuser", "password123", "a".repeat(101));

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isBadRequest());
        }

        // AC14: username with spaces → 400
        @Test
        void shouldReturn400_whenUsernameContainsSpaces() throws Exception {
            RegisterRequest req = buildRegisterRequest("user name", "password123", "Name");

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isBadRequest());
        }

        // AC14: username with special chars → 400
        @Test
        void shouldReturn400_whenUsernameContainsSpecialChars() throws Exception {
            RegisterRequest req = buildRegisterRequest("user@name!", "password123", "Name");

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isBadRequest());
        }

        // AC14: username with hyphen → 400
        @Test
        void shouldReturn400_whenUsernameContainsHyphen() throws Exception {
            RegisterRequest req = buildRegisterRequest("user-name", "password123", "Name");

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isBadRequest());
        }

        // AC14: username with underscore → 201 (allowed)
        @Test
        void shouldReturn201_whenUsernameContainsUnderscore() throws Exception {
            RegisterRequest req = buildRegisterRequest("user_name", "password123", "Name");

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isCreated());
        }

        // Missing username field → 400
        @Test
        void shouldReturn400_whenUsernameMissing() throws Exception {
            String json = "{\"password\":\"password123\",\"displayName\":\"Name\"}";

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(json))
                    .andExpect(status().isBadRequest());
        }

        // Missing password field → 400
        @Test
        void shouldReturn400_whenPasswordMissing() throws Exception {
            String json = "{\"username\":\"validuser\",\"displayName\":\"Name\"}";

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(json))
                    .andExpect(status().isBadRequest());
        }

        // Missing displayName field → 400
        @Test
        void shouldReturn400_whenDisplayNameMissing() throws Exception {
            String json = "{\"username\":\"validuser\",\"password\":\"password123\"}";

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(json))
                    .andExpect(status().isBadRequest());
        }

        // AC3: password stored as bcrypt hash, not plaintext
        @Test
        void shouldStoreBcryptHash_notPlaintext() throws Exception {
            RegisterRequest req = buildRegisterRequest("hashcheck", "password123", "Hash Check");

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isCreated());

            User stored = userRepository.findByUsername("hashcheck").orElseThrow();
            assertTrue(stored.getPassword().startsWith("$2a$") || stored.getPassword().startsWith("$2b$"),
                    "Password should be bcrypt encoded");
            assertNotEquals("password123", stored.getPassword());
        }
    }

    // =============================================
    // POST /api/auth/login
    // =============================================

    @Nested
    class LoginEndpoint {

        @BeforeEach
        void setUpUser() {
            createUserInDb("loginuser", "password123", "Login User");
        }

        // AC4: login success 200 with token and expiresIn
        @Test
        void shouldReturn200WithTokenAndExpiresIn_whenValidCredentials() throws Exception {
            LoginRequest req = buildLoginRequest("loginuser", "password123");

            mockMvc.perform(post("/api/auth/login")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.token").isString())
                    .andExpect(jsonPath("$.token").isNotEmpty())
                    .andExpect(jsonPath("$.expiresIn").value(86400));
        }

        // AC4: contract — response has exactly token and expiresIn
        @Test
        void shouldReturnExactLoginResponseSchema() throws Exception {
            LoginRequest req = buildLoginRequest("loginuser", "password123");

            mockMvc.perform(post("/api/auth/login")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.token").exists())
                    .andExpect(jsonPath("$.expiresIn").exists())
                    .andExpect(jsonPath("$.id").doesNotExist())
                    .andExpect(jsonPath("$.username").doesNotExist())
                    .andExpect(jsonPath("$.password").doesNotExist());
        }

        // AC4: returned token should be a valid JWT
        @Test
        void shouldReturnValidJwtToken() throws Exception {
            LoginRequest req = buildLoginRequest("loginuser", "password123");

            MvcResult result = mockMvc.perform(post("/api/auth/login")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isOk())
                    .andReturn();

            String responseBody = result.getResponse().getContentAsString();
            String token = objectMapper.readTree(responseBody).get("token").asText();

            assertTrue(jwtTokenProvider.validateToken(token), "Returned token should be valid");
        }

        // AC5: wrong password → 401
        @Test
        void shouldReturn401_whenWrongPassword() throws Exception {
            LoginRequest req = buildLoginRequest("loginuser", "wrongpassword");

            mockMvc.perform(post("/api/auth/login")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isUnauthorized())
                    .andExpect(jsonPath("$.message").exists());
        }

        // AC6: nonexistent user → 401
        @Test
        void shouldReturn401_whenUserDoesNotExist() throws Exception {
            LoginRequest req = buildLoginRequest("nonexistent", "password123");

            mockMvc.perform(post("/api/auth/login")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(req)))
                    .andExpect(status().isUnauthorized())
                    .andExpect(jsonPath("$.message").exists());
        }

        // BR7: no user enumeration — same error message for wrong password vs nonexistent user
        @Test
        void shouldReturnSameErrorMessage_forWrongPasswordAndNonexistentUser() throws Exception {
            MvcResult wrongPwResult = mockMvc.perform(post("/api/auth/login")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(buildLoginRequest("loginuser", "wrongpassword"))))
                    .andExpect(status().isUnauthorized())
                    .andReturn();

            MvcResult noUserResult = mockMvc.perform(post("/api/auth/login")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(toJson(buildLoginRequest("nonexistent", "password123"))))
                    .andExpect(status().isUnauthorized())
                    .andReturn();

            String wrongPwMsg = objectMapper.readTree(wrongPwResult.getResponse().getContentAsString())
                    .get("message").asText();
            String noUserMsg = objectMapper.readTree(noUserResult.getResponse().getContentAsString())
                    .get("message").asText();

            assertEquals(wrongPwMsg, noUserMsg,
                    "Error messages should be identical to prevent user enumeration");
        }

        // Empty body → 400
        @Test
        void shouldReturn400_whenEmptyBody() throws Exception {
            mockMvc.perform(post("/api/auth/login")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content("{}"))
                    .andExpect(status().isBadRequest());
        }
    }

